public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // ── Construction & Getters ──
        try {
            Superhero mr = new Superhero("Mr. Incredible", "Super strength", 95);
            check("getName()", "Mr. Incredible", mr.getName());
        } catch (Exception e) { fail("getName()", e); }

        try {
            Superhero mr = new Superhero("Mr. Incredible", "Super strength", 95);
            check("getPower()", "Super strength", mr.getPower());
        } catch (Exception e) { fail("getPower()", e); }

        try {
            Superhero mr = new Superhero("Mr. Incredible", "Super strength", 95);
            check("getStrengthLevel()", "95",
                  String.valueOf(mr.getStrengthLevel()));
        } catch (Exception e) { fail("getStrengthLevel()", e); }

        // ── toString ──
        try {
            Superhero mr = new Superhero("Mr. Incredible", "Super strength", 95);
            check("toString()",
                  "Mr. Incredible | Power: Super strength | Strength: 95",
                  mr.toString());
        } catch (Exception e) { fail("toString()", e); }

        try {
            Superhero vi = new Superhero("Violet", "Invisibility", 70);
            check("toString() — Violet",
                  "Violet | Power: Invisibility | Strength: 70",
                  vi.toString());
        } catch (Exception e) { fail("toString() — Violet", e); }

        // ── equals: same name & power → true ──
        try {
            Superhero a = new Superhero("Dash", "Super speed", 85);
            Superhero b = new Superhero("Dash", "Super speed", 60);
            check("equals() — same name & power, different strength",
                  "true", String.valueOf(a.equals(b)));
        } catch (Exception e) { fail("equals() — same name & power", e); }

        // ── equals: different name → false ──
        try {
            Superhero a = new Superhero("Dash", "Super speed", 85);
            Superhero b = new Superhero("Elastigirl", "Super speed", 85);
            check("equals() — different name",
                  "false", String.valueOf(a.equals(b)));
        } catch (Exception e) { fail("equals() — different name", e); }

        // ── equals: different power → false ──
        try {
            Superhero a = new Superhero("Dash", "Super speed", 85);
            Superhero b = new Superhero("Dash", "Invisibility", 85);
            check("equals() — different power",
                  "false", String.valueOf(a.equals(b)));
        } catch (Exception e) { fail("equals() — different power", e); }

        // ── equals: null → false ──
        try {
            Superhero a = new Superhero("Dash", "Super speed", 85);
            check("equals(null) → false",
                  "false", String.valueOf(a.equals(null)));
        } catch (Exception e) { fail("equals(null)", e); }

        // ── equals: wrong type → false ──
        try {
            Superhero a = new Superhero("Dash", "Super speed", 85);
            check("equals(String) → false",
                  "false", String.valueOf(a.equals("Dash")));
        } catch (Exception e) { fail("equals(String)", e); }

        // ── findStrongest ──
        try {
            Superhero[] team = {
                new Superhero("Mr. Incredible", "Super strength", 95),
                new Superhero("Elastigirl", "Elasticity", 80),
                new Superhero("Violet", "Invisibility", 70),
                new Superhero("Dash", "Super speed", 85),
                new Superhero("Frozone", "Ice powers", 78)
            };
            Superhero strongest = Superhero.findStrongest(team);
            check("findStrongest() returns Mr. Incredible",
                  "Mr. Incredible", strongest.getName());
        } catch (Exception e) { fail("findStrongest()", e); }

        try {
            Superhero[] team = {
                new Superhero("Violet", "Invisibility", 70),
                new Superhero("Dash", "Super speed", 85)
            };
            Superhero strongest = Superhero.findStrongest(team);
            check("findStrongest() with 2-element array",
                  "Dash", strongest.getName());
        } catch (Exception e) { fail("findStrongest() 2-element", e); }

        // ── findStrongest: empty array → null ──
        try {
            Superhero[] empty = {};
            Superhero result = Superhero.findStrongest(empty);
            check("findStrongest([]) → null",
                  "true", String.valueOf(result == null));
        } catch (Exception e) { fail("findStrongest([])", e); }

        // ── Encapsulation ──
        try {
            java.lang.reflect.Field f = Superhero.class.getDeclaredField("name");
            check("name is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("name field exists", new Exception("Field 'name' not found"));
        } catch (Exception e) { fail("name is private", e); }

        // ── findStrongest is static ──
        try {
            java.lang.reflect.Method m = Superhero.class.getDeclaredMethod(
                "findStrongest", Superhero[].class);
            check("findStrongest is static", "true",
                  String.valueOf(java.lang.reflect.Modifier.isStatic(m.getModifiers())));
        } catch (NoSuchMethodException e) {
            fail("findStrongest method exists",
                 new Exception("Method findStrongest(Superhero[]) not found"));
        } catch (Exception e) { fail("findStrongest is static", e); }
    }

    // ── Helpers ──
    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " — expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " — " + e.getMessage()); failed++;
    }
}
